[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": ""}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "{% set currency = frappe.db.get_value(
    "Company",
    doc.company,
    "default_currency"
) or "PKR" %}

{% set total_debit = frappe.utils.flt(doc.total_debit or 0) %}
{% set total_credit = frappe.utils.flt(doc.total_credit or 0) %}

<style>
.print-heading {
    border: 0 !important;
    display: none !important;
    height: 0 !important;
    margin: 0 !important;
    padding: 0 !important;
}

.print-format .letter-head {
    margin-bottom: 12px !important;
}

.pv {
    color: #111;
    font-family: Arial, sans-serif;
    font-size: 10px;
    width: 100%;
}

.pv * {
    box-sizing: border-box;
}

.pv-title {
    font-family: Georgia, "Times New Roman", serif;
    font-size: 20px;
    font-weight: bold;
    margin: 10px 0 14px;
    text-align: center;
}

.pv-meta,
.pv-table,
.pv-signatures {
    border-collapse: collapse;
    table-layout: fixed;
    width: 100%;
}

.pv-meta {
    margin-bottom: 12px;
}

.pv-meta td {
    border: 0 !important;
    height: 28px;
    line-height: 1.25;
    padding: 4px 6px !important;
    vertical-align: middle !important;
}

.pv-label {
    font-weight: bold;
    white-space: nowrap;
    width: 13%;
}

.pv-value {
    overflow-wrap: anywhere;
    width: 20.33%;
}

.pv-table th,
.pv-table td {
    border: 1px solid #222 !important;
    line-height: 1.3;
    padding: 6px !important;
    vertical-align: top !important;
}

.pv-table th {
    background: #eee !important;
    font-weight: bold;
    text-align: center;
}

.pv-sr {
    text-align: center;
    width: 5%;
}

.pv-account {
    overflow-wrap: anywhere;
    width: 30%;
}

.pv-party {
    overflow-wrap: anywhere;
    width: 15%;
}

.pv-cheque {
    overflow-wrap: anywhere;
    width: 12%;
}

.pv-territory {
    overflow-wrap: anywhere;
    width: 11%;
}

.pv-money {
    text-align: right;
    width: 13.5%;
}

.pv-total-label,
.pv-total-amount {
    font-weight: bold;
    text-align: right;
}

.pv-notes {
    margin-top: 14px;
}

.pv-notes p {
    margin: 0 0 14px;
}

.pv-note-label {
    font-weight: bold;
}

.pv-signatures {
    margin-top: 70px;
}

.pv-signatures td {
    border: 0 !important;
    padding: 0 15px !important;
    text-align: center;
    vertical-align: bottom !important;
    width: 25%;
}

.pv-signature {
    border-top: 1px solid #111;
    display: block;
    padding-top: 6px;
}

@media print {
    .pv-meta,
    .pv-notes,
    .pv-signatures {
        page-break-inside: avoid;
    }

    .pv-table thead {
        display: table-header-group;
    }

    .pv-table tr {
        page-break-inside: avoid;
    }
}
</style>

<div class="pv">

    <div class="pv-title">
        Payment Voucher
    </div>

    <table class="pv-meta">
        <tbody>
            <tr>
                <td class="pv-label">Voucher No:</td>
                <td class="pv-value">
                    {{ doc.name or "-" }}
                </td>

                <td class="pv-label">Date:</td>
                <td class="pv-value">
                    {% if doc.posting_date %}
                        {{ frappe.utils.format_date(
                            doc.posting_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% else %}
                        -
                    {% endif %}
                </td>

                <td class="pv-label">Payment Type:</td>
                <td class="pv-value">
                    {{ doc.voucher_type or "-" }}
                </td>
            </tr>

            <tr>
                <td class="pv-label">Mode of Payment:</td>
                <td class="pv-value">
                    {{ doc.mode_of_payment or "-" }}
                </td>

                <td class="pv-label">Reference No:</td>
                <td class="pv-value">
                    {{ doc.cheque_no or "-" }}
                </td>

                <td class="pv-label">Reference Date:</td>
                <td class="pv-value">
                    {% if doc.cheque_date %}
                        {{ frappe.utils.format_date(
                            doc.cheque_date,
                            "dd-MM-yyyy"
                        ) }}
                    {% else %}
                        -
                    {% endif %}
                </td>
            </tr>
        </tbody>
    </table>

    <table class="pv-table">
        <thead>
            <tr>
                <th class="pv-sr">Sr.</th>
                <th class="pv-account">Account</th>
                <th class="pv-party">Party</th>
                <th class="pv-cheque">Cheque No</th>
                <th class="pv-territory">Territory</th>
                <th class="pv-money">Debit ({{ currency }})</th>
                <th class="pv-money">Credit ({{ currency }})</th>
            </tr>
        </thead>

        <tbody>
            {% for row in doc.accounts %}

                {% set territory =
                    row.get("territory")
                    or row.get("custom_territory")
                %}

                {% if not territory
                    and row.party
                    and row.party_type == "Customer" %}

                    {% set territory = frappe.db.get_value(
                        "Customer",
                        row.party,
                        "territory"
                    ) %}

                {% elif not territory
                    and row.party
                    and row.party_type == "Donor" %}

                    {% set territory = frappe.db.get_value(
                        "Donor",
                        row.party,
                        "territory"
                    ) %}

                {% endif %}

                <tr>
                    <td class="pv-sr">
                        {{ loop.index }}
                    </td>

                    <td class="pv-account">
                        {{ row.account or "-" }}
                    </td>

                    <td class="pv-party">
                        {{ row.party or "-" }}
                    </td>

                    <td class="pv-cheque">
                        {{ doc.cheque_no or "-" }}
                    </td>

                    <td class="pv-territory">
                        {{ territory or "-" }}
                    </td>

                    <td class="pv-money">
                        {% if frappe.utils.flt(row.debit) %}
                            {{ frappe.utils.fmt_money(
                                row.debit,
                                currency=currency
                            ) }}
                        {% else %}
                            -
                        {% endif %}
                    </td>

                    <td class="pv-money">
                        {% if frappe.utils.flt(row.credit) %}
                            {{ frappe.utils.fmt_money(
                                row.credit,
                                currency=currency
                            ) }}
                        {% else %}
                            -
                        {% endif %}
                    </td>
                </tr>

            {% endfor %}

            <tr>
                <td class="pv-total-label" colspan="5">
                    Total:
                </td>

                <td class="pv-total-amount">
                    {{ frappe.utils.fmt_money(
                        total_debit,
                        currency=currency
                    ) }}
                </td>

                <td class="pv-total-amount">
                    {{ frappe.utils.fmt_money(
                        total_credit,
                        currency=currency
                    ) }}
                </td>
            </tr>
        </tbody>
    </table>

    <div class="pv-notes">
        <p>
            <span class="pv-note-label">Remark:</span>
            {{ doc.user_remark or "-" }}
        </p>

        <p>
            <span class="pv-note-label">
                Amount in Words:
            </span>

            {{ frappe.utils.money_in_words(
                total_debit,
                currency
            ) }}
        </p>
    </div>

    <table class="pv-signatures">
        <tbody>
            <tr>
                <td>
                    <span class="pv-signature">Prepared By</span>
                </td>

                <td>
                    <span class="pv-signature">Checked By</span>
                </td>

                <td>
                    <span class="pv-signature">
                        Manager Finance
                    </span>
                </td>

                <td>
                    <span class="pv-signature">
                        Approved By / CEO
                    </span>
                </td>
            </tr>
        </tbody>
    </table>

</div>"}]
